('P14', '陽炎', '幻影殘像・陽炎之舞', 'physical', 'passive', '被動技能。有機率完全迴避物理攻擊。觸發機率隨等級提升（每級+3%）。', '火', 0, 0, 0, 10, 0, NULL, '{"isPassive":true,"passiveType":"dodge","passiveTriggerChance":3,"passiveChancePerLevel":3,"aoe":"self","aoeDescription":"被動（迴避）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'self', 'none', 'rare', 1, 1, NULL, 114, 1774744854767, 1774744854767),
